/// Simulate complete TUI app lifecycle
#[test]
fn test_full_stack_app() {
    // Create app with bubbles components styled with lipgloss
    struct App {
        list: bubbles::list::List,
        input: bubbles::textinput::TextInput,
        style: lipgloss::Style,
    }

    impl Model for App {
        fn init(&self) -> Cmd {
            Cmd::none()
        }

        fn update(&self, msg: Msg) -> (Self, Cmd) {
            // Handle updates
        }

        fn view(&self) -> String {
            let list_view = self.list.view();
            let input_view = self.input.view();
            self.style.render(&format!("{}\n{}", list_view, input_view))
        }
    }

    // Simulate user interaction
    let app = App::new();

    // Type in input
    let (app, _) = app.update(Msg::Key(KeyMsg::char('H')));
    let (app, _) = app.update(Msg::Key(KeyMsg::char('i')));

    // Switch to list
    let (app, _) = app.update(Msg::Key(KeyMsg { key_type: KeyType::Tab, ..Default::default() }));

    // Select item
    let (app, _) = app.update(Msg::Key(KeyMsg { key_type: KeyType::Down, ..Default::default() }));
    let (app, _) = app.update(Msg::Key(KeyMsg { key_type: KeyType::Enter, ..Default::default() }));

    // Verify final state
    assert_eq!(app.input.value(), "Hi");
    assert_eq!(app.list.selected_index(), 1);
}
