### Scenario 3: Animated Progress Display
```rust
/// E2E: Progress bar with animation
#[test]
fn test_animated_progress() {
    struct DownloadApp {
        progress: bubbles::progress::Progress,
        spinner: bubbles::spinner::Spinner,
    }

    impl Model for DownloadApp {
        fn init(&self) -> Cmd {
            bubbles::spinner::tick()
        }

        fn update(&self, msg: Msg) -> (Self, Cmd) {
            match msg {
                Msg::Progress(pct) => {
                    (Self { progress: self.progress.set_percent(pct), ..self }, Cmd::none())
                }
                Msg::SpinnerTick => {
                    let (spinner, cmd) = self.spinner.update(msg);
                    (Self { spinner, ..self }, cmd)
                }
                _ => (self, Cmd::none())
            }
        }

        fn view(&self) -> String {
            if self.progress.percent() < 1.0 {
                format!("{} Downloading... {}", self.spinner.view(), self.progress.view())
            } else {
                "✓ Complete!".to_string()
            }
        }
    }

    let app = DownloadApp::new();

    // Simulate download progress
    let (app, _) = app.update(Msg::Progress(0.25));
    assert!(app.view().contains("Downloading"));

    let (app, _) = app.update(Msg::Progress(1.0));
    assert!(app.view().contains("Complete"));
}
```

