+        gravity,
+    );
+
+    let new_pos = projectile.update();
+    let new_vel = projectile.velocity();
+
+    // Check position (use looser epsilon due to floating point differences)
+    if !approx_eq(new_pos.x, expected.x, PROJECTILE_EPSILON) {
