+    // Run each test
+    for test in &fixtures.tests {
+        let result = run_test(test);
+        // Store the test name by leaking since we need 'static lifetime
+        let name: &'static str = Box::leak(test.name.clone().into_boxed_str());
+        results.push((name, result));
+    }
